class Solution:
    def findMode(self, root):
        counts = {}
        def walk(node):
            if node is None:
                return
            counts[node.val] = counts.get(node.val, 0) + 1
            walk(node.left)
            walk(node.right)
        walk(root)
        hi = max(counts.values())
        return [v for v, c in counts.items() if c == hi]

