var findMode = function(root) {
    const counts = new Map();
    const walk = (node) => {
        if (node === null) return;
        counts.set(node.val, (counts.get(node.val) || 0) + 1);
        walk(node.left);
        walk(node.right);
    };
    walk(root);
    let hi = 0;
    for (const c of counts.values()) if (c > hi) hi = c;
    const res = [];
    for (const [v, c] of counts.entries()) if (c === hi) res.push(v);
    return res;
};
